import React, { createContext, useState, useContext, useEffect } from 'react';

const AuthContext = createContext();

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) throw new Error('useAuth must be used within AuthProvider');
  return context;
};

// قائمة الكاشير المؤقتة (يمكن استبدالها بقاعدة بيانات)
const CASHIERS = [
  { id: '1001', password: '1234', name: 'أحمد محمد' },
  { id: '1002', password: '1234', name: 'سارة علي' },
  { id: '1003', password: '1234', name: 'خالد عمر' },
];

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // استعادة الجلسة من localStorage
    const storedUser = localStorage.getItem('pos_user');
    if (storedUser) {
      setUser(JSON.parse(storedUser));
    }
    setLoading(false);
  }, []);

  const login = (id, password) => {
    const cashier = CASHIERS.find(c => c.id === id && c.password === password);
    if (cashier) {
      const userData = { id: cashier.id, name: cashier.name };
      setUser(userData);
      localStorage.setItem('pos_user', JSON.stringify(userData));
      return true;
    }
    return false;
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem('pos_user');
  };

  const value = { user, login, logout, loading };

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
};
